#include <bits/stdc++.h>
using namespace std;
string a;
int main() {
	int n;
	cin>>n;
	for(int i=0; i<n; i++) {
		cin>>a;
		bool z[4]= {1,1,1,1};
		for(int j=0; j<a.size(); j++) {
			if(a[j]>='2') {
				z[0]=0;
			}
			if(a[j]>='8') {
				z[1]=0;
			}
			if(a[j]>'9') {
				z[2]=0;
			}
			if(a[j]>'F') {
				z[3]=0;
			}
		}
		cout<<z[0]<<" "<<z[1]<<" "<<z[2]<<" "<<z[3]<<"\n";
	}
	return 0;
}
